<?php
namespace App\Domain\Equipment;use App\Domain\Inventory\ItemClassification;use App\Domain\WorldCatalog\ItemType;use App\Models\Item;use InvalidArgumentException;
final class EquippableItemValidator{private $classification;public function __construct(ItemClassification $classification){$this->classification=$classification;}public function equipmentType(Item $item){if($item->equipment_type===null){if($item->item_type===ItemType::EQUIPMENT)throw new InvalidArgumentException('Equipment Item requires equipment_type.');return null;}EquipmentType::assertValid($item->equipment_type);if($item->item_type!==ItemType::EQUIPMENT||$this->classification->classify($item)!==ItemClassification::UNIQUE)throw new InvalidArgumentException('Invalid equippable Item classification.');return$item->equipment_type;}public function assertCompatible(Item $item,$slot){$type=$this->equipmentType($item);if($type===null||CharacterEquipmentSlot::equipmentType($slot)!==$type)throw new InvalidArgumentException('Item is not compatible with the equipment slot.');return$type;}}
